#!/usr/bin/env python3
"""Run this on VPS: python3 fix_vps_products.py"""
import base64, os

ADD_B64  = ""
EDIT_B64 = ""

add_path  = "/var/www/mahalaxmi-nextjs/frontend/app/(admin)/admin/products/add/page.tsx"
edit_path = "/var/www/mahalaxmi-nextjs/frontend/app/(admin)/admin/products/[id]/page.tsx"

open(add_path,  'wb').write(base64.b64decode(ADD_B64))
open(edit_path, 'wb').write(base64.b64decode(EDIT_B64))

print("add/page.tsx  ->", os.path.getsize(add_path),  "bytes")
print("[id]/page.tsx ->", os.path.getsize(edit_path), "bytes")
print("Done! Ab VPS pe build karo:")
print("  cd /var/www/mahalaxmi-nextjs/frontend && npm run build && pm2 restart mahalaxmi-frontend")
